unistr('                    <tr><td>\D83C\DF93 Tech Symposium</td><td>May 15, 2026</td><td>Block C Hall</td><td><span class="status-badge status-completed">Completed</span></td></tr>'),
unistr('                    <tr><td>\D83E\DD16 AI Summit</td><td>May 20, 2026</td><td>Main Auditorium</td><td><span class="status-badge status-completed">Completed</span></td></tr>'),
