,p_javascript_code_onload=>wwv_flow_string.join(wwv_flow_t_varchar2(
'function forceTableVisible() {',
'    let table = document.querySelector(''.a-IRR-table'');',
'    if (table) {',
'        table.style.setProperty(''opacity'', ''1'', ''important'');',
'        table.style.setProperty(''visibility'', ''visible'', ''important'');',
'        table.style.setProperty(''display'', ''block'', ''important'');',
'        ',
'        // Sab rows aur cells ke liye',
'        let rows = table.querySelectorAll(''tr'');',
'        rows.forEach(r => {',
'            r.style.setProperty(''display'', ''table-row'', ''important'');',
'            r.style.setProperty(''opacity'', ''1'', ''important'');',
'        });',
'        let cells = table.querySelectorAll(''td, th'');',
'        cells.forEach(c => {',
'            c.style.setProperty(''display'', ''table-cell'', ''important'');',
'            c.style.setProperty(''opacity'', ''1'', ''important'');',
'        });',
'    }',
'}',
'',
'// Pehle turant chalayein',
'forceTableVisible();',
'',
'// Har 500ms mein chalayein (kisi bhi refresh par)',
'setInterval(forceTableVisible, 500);',
'',
'// Jab bhi Interactive Report refresh ho',
'if (typeof apex !== ''undefined'') {',
'    apex.event.subscribe(''apexafterrefresh'', forceTableVisible);',
'}',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'function lightBackgroundFix() {',
'    // Remove any dark background from body',
'    document.body.style.background = "#f0f2f5";',
'    let content = document.querySelector(''.t-Body-content'');',
'    if (content) content.style.background = "#ffffff";',
'    ',
'    // Ensure table visible',
'    let table = document.querySelector(''.a-IRR-table'');',
'    if (table) {',
'        table.style.opacity = "1";',
'        table.style.visibility = "visible";',
'        let rows = table.querySelectorAll(''tr'');',
'        rows.forEach(row => {',
'            row.style.opacity = "1";',
'        });',
'    }',
'}',
'lightBackgroundFix();',
'setInterval(lightBackgroundFix, 500);'))
,p_inline_css=>wwv_flow_string.join(wwv_flow_t_varchar2(
'/* =======================================================',
