'    color: #8B5E3C;',
'    letter-spacing: 2px;',
'}',
'',
'.university-campus {',
'    font-size: 16px;',
'    color: #5C3A21;',
'    margin-top: 5px;',
'    font-weight: 500;',
'}',
'',
