'    font-size: 12px;',
'    color: #666;',
'    margin-bottom: 30px;',
'}',
'',
'.cert-border-line {',
'    width: 80%;',
'    height: 2px;',
'    background: linear-gradient(90deg, transparent, #8B5E3C, #8B5E3C, transparent);',
'    margin: 20px auto;',
'}',
'',
'.cert-title {',
'    font-size: 48px;',
'    font-weight: bold;',
'    color: #5C3A21;',
'    margin: 20px 0;',
'    font-family: ''Times New Roman'', serif;',
'}',
'',
'.cert-student-name {',
'    font-size: 36px;',
'    font-weight: bold;',
'    color: #8B5E3C;',
'    margin: 20px 0;',
'    border-bottom: 2px solid #8B5E3C;',
'    display: inline-block;',
'    padding: 0 20px;',
'}',
'',
