'    font-size: 22px;',
'    font-weight: bold;',
'    color: #5C3A21;',
'    margin: 15px 0;',
'}',
'',
'.cert-event {',
'    font-size: 24px;',
'    font-weight: bold;',
'    color: #8B5E3C;',
'    margin: 15px 0;',
'}',
'',
