'    margin-top: 40px;',
'    display: flex;',
'    justify-content: space-around;',
'}',
'',
'.signature {',
'    text-align: center;',
'}',
'',
'.signature .line {',
'    width: 200px;',
'    border-top: 1px solid #333;',
'    margin-top: 40px;',
'}',
'',
