'    font-size: 12px;',
'    margin-top: 5px;',
'}',
'',
'.action-buttons {',
'    display: flex;',
'    justify-content: center;',
'    gap: 20px;',
'    margin-top: 25px;',
'}',
'',
'.page-title {',
'    text-align: center;',
'    font-size: 32px;',
'    font-weight: bold;',
'    color: #1e3a5f;',
'    margin-bottom: 20px;',
'    padding-bottom: 10px;',
'    border-bottom: 3px solid #8B5E3C;',
'    display: inline-block;',
'    width: auto;',
'}',
'',
'.title-container {',
'    text-align: center;',
'}',
'',
'.alert-success {',
'    background: #d4edda;',
'    color: #155724;',
'    padding: 12px;',
'    border-radius: 8px;',
'    margin-bottom: 20px;',
'    text-align: center;',
'    display: none;',
'}',
'</style>',
'',
'<!-- html2pdf Library for PDF Download -->',
'<script src="https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js" integrity="sha512-GsLlZN/3F2ErC5ifS5QtgpiJtWd43JWSuIgh7mbzZ8zBps+dvLusV+eNQATqgA/HdeKFVgA5v3S/cIrLF7QnIg==" crossorigin="anonymous" referrerpolicy="no-refe'
||'rrer"></script>',
'',
'<div class="certificate-wrapper">',
'    <div class="title-container">',
unistr('        <h1 class="page-title">\D83C\DF93 Certificate Generator</h1>'),
'    </div>',
'',
'    <div id="successMessage" class="alert-success">',
unistr('        \2705 Certificate generated successfully!'),
'    </div>',
'',
'    <!-- Input Form -->',
'    <div class="form-container">',
unistr('        <h3 style="text-align:center; margin-bottom:20px;">\D83D\DCDD Certificate Details</h3>'),
'        <div class="form-row">',
'            <div class="form-group">',
unistr('                <label>\D83D\DC64 Student Name:</label>'),
'                <input type="text" id="studentName" placeholder="Enter Student Full Name">',
'            </div>',
'            <div class="form-group">',
unistr('                <label>\D83D\DCC5 Event Name:</label>'),
'                <input type="text" id="eventName" placeholder="Enter Event Name">',
'            </div>',
'            <div class="form-group">',
unistr('                <label>\D83C\DFC6 Achievement:</label>'),
'                <input type="text" id="achievement" placeholder="e.g., 1st Prize, Participation" value="Certificate of Achievement">',
'            </div>',
'            <div class="form-group">',
unistr('                <label>\D83D\DCC6 Issue Date:</label>'),
'                <input type="date" id="issueDate">',
'            </div>',
'        </div>',
'        <div style="text-align: center;">',
unistr('            <button id="generateCertBtn" type="button" class="btn btn-primary">\2728 Generate Certificate</button>'),
'        </div>',
'    </div>',
'',
'    <!-- Certificate Preview -->',
'    <div id="certificatePreview" style="display: none;">',
'        <div class="cert-card" id="certificateToPrint">',
unistr('            <div class="university-logo">\D83C\DFDB\FE0F</div>'),
'            <div class="university-name">COMSATS University Islamabad</div>',
'            <div class="university-campus">Islamabad Campus</div>',
'            <div class="university-sub">(Recognized by Higher Education Commission)</div>',
'            <div class="cert-border-line"></div>',
unistr('            <div style="font-size: 14px; letter-spacing: 3px; color: #8B5E3C;">\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501\2501</div>'),
'            <div style="font-size: 12px; margin: 5px 0;">OFFICIAL CERTIFICATE OF ACHIEVEMENT</div>',
'            <div class="cert-title">CERTIFICATE</div>',
'            <div style="font-size: 16px;">This certificate is proudly presented to</div>',
'            <div id="certStudentName" class="cert-student-name">__________</div>',
'            <div style="font-size: 16px; margin: 20px 0;">for outstanding achievement as</div>',
'            <div id="certAchievement" class="cert-achievement">__________</div>',
'            <div style="font-size: 16px; margin: 20px 0;">in the event of</div>',
'            <div id="certEvent" class="cert-event">__________</div>',
'            <div class="cert-border-line"></div>',
'            <div class="signature-line">',
'                <div class="signature"><div class="line"></div><div class="label">Date: <span id="certDateDisplay">__________</span></div></div>',
'                <div class="signature"><div class="line"></div><div class="label">Club Coordinator</div></div>',
'                <div class="signature"><div class="line"></div><div class="label">Dean of Students</div></div>',
'            </div>',
'            <div style="font-size: 12px; margin-top: 30px; color: #999;">Certificate ID: <span id="certId">XXXX</span></div>',
'        </div>',
'    </div>',
'    ',
'    <div id="actionButtons" style="display: none; text-align: center; margin-top: 20px;">',
'        <div class="action-buttons">',
unistr('            <button id="printCertBtn" type="button" class="btn btn-warning">\D83D\DDA8\FE0F Print Certificate</button>'),
'        </div>',
'    </div>',
'</div>',
'',
'<script>',
'// ========== GENERATE CERTIFICATE PREVIEW ==========',
'function generateCertificate() {',
'    var studentName = document.getElementById(''studentName'').value;',
'    var eventName = document.getElementById(''eventName'').value;',
'    var achievement = document.getElementById(''achievement'').value;',
'    var issueDate = document.getElementById(''issueDate'').value;',
'    var messageDiv = document.getElementById(''successMessage'');',
'    ',
'    if(!studentName) { alert(''Please enter Student Name!''); return; }',
'    if(!eventName) { alert(''Please enter Event Name!''); return; }',
'    if(!achievement) { alert(''Please enter Achievement!''); return; }',
'    if(!issueDate) { alert(''Please select Issue Date!''); return; }',
'    ',
'    // Generate random Certificate ID',
'    var certId = Math.floor(Math.random() * 100000);',
'    ',
'    // Update certificate preview',
'    document.getElementById(''certStudentName'').innerHTML = studentName;',
'    document.getElementById(''certEvent'').innerHTML = eventName;',
'    document.getElementById(''certAchievement'').innerHTML = achievement;',
'    document.getElementById(''certDateDisplay'').innerHTML = issueDate;',
'    document.getElementById(''certId'').innerHTML = certId;',
'    ',
'    // Show certificate preview and buttons',
'    document.getElementById(''certificatePreview'').style.display = ''block'';',
'    document.getElementById(''actionButtons'').style.display = ''block'';',
'    ',
'    // Show success message',
'    messageDiv.style.display = ''block'';',
'    setTimeout(function() { messageDiv.style.display = ''none''; }, 3000);',
'    ',
'    // Clear form',
'    document.getElementById(''studentName'').value = '''';',
'    document.getElementById(''eventName'').value = '''';',
'    document.getElementById(''achievement'').value = ''Certificate of Achievement'';',
'    document.getElementById(''issueDate'').value = today;',
'    ',
'    // Scroll to certificate',
'    document.getElementById(''certificatePreview'').scrollIntoView({ behavior: ''smooth'', block: ''start'' });',
'}',
'',
'// ========== PRINT CERTIFICATE ==========',
'function printCertificate() {',
'    var printContent = document.getElementById(''certificateToPrint'').innerHTML;',
'    var printWindow = window.open('''', ''_blank'');',
'    printWindow.document.write(''<html><head><title>Certificate</title>'');',
'    printWindow.document.write(''<style>'');',
'    printWindow.document.write(''body{padding:40px;font-family:serif;text-align:center;}'');',
'    printWindow.document.write(''.cert-card{border:12px double #8B5E3C;background:linear-gradient(135deg,#fffef7,#fff8e7);padding:50px;text-align:center;border-radius:24px;margin:20px 0;}'');',
'    printWindow.document.write(''.university-name{font-size:28px;font-weight:bold;color:#8B5E3C;}'');',
'    printWindow.document.write(''.university-campus{font-size:16px;color:#5C3A21;}'');',
'    printWindow.document.write(''.cert-title{font-size:48px;font-weight:bold;color:#5C3A21;margin:20px 0;}'');',
'    printWindow.document.write(''.cert-student-name{font-size:36px;font-weight:bold;color:#8B5E3C;border-bottom:2px solid #8B5E3C;}'');',
'    printWindow.document.write(''.cert-achievement{font-size:22px;font-weight:bold;color:#5C3A21;}'');',
'    printWindow.document.write(''.cert-event{font-size:24px;font-weight:bold;color:#8B5E3C;}'');',
'    printWindow.document.write(''.signature-line{display:flex;justify-content:space-around;margin-top:40px;}'');',
'    printWindow.document.write(''.signature{text-align:center;}'');',
'    printWindow.document.write(''.signature .line{width:200px;border-top:1px solid #333;margin-top:40px;}'');',
'    printWindow.document.write(''</style>'');',
'    printWindow.document.write(''</head><body>'' + printContent + ''</body></html>'');',
'    printWindow.document.close();',
'    printWindow.print();',
'    printWindow.close();',
'}',
'',
'// ========== EVENT LISTENERS ==========',
'document.getElementById(''generateCertBtn'').onclick = generateCertificate;',
'document.getElementById(''printCertBtn'').onclick = printCertificate;',
'',
'// ========== SET TODAY''S DATE AS DEFAULT ==========',
'var today = new Date().toISOString().split(''T'')[0];',
'document.getElementById(''issueDate'').value = today;',
'</script>'))
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'expand_shortcuts', 'N',
  'output_as', 'HTML')).to_clob
,p_created_on=>wwv_flow_imp.dz('20260530151004Z')
,p_updated_on=>wwv_flow_imp.dz('20260610074254Z')
,p_created_by=>'ROZEENUMEED71@GMAIL.COM'
,p_updated_by=>'ROZEENUMEED71@GMAIL.COM'
);
end;
